</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1rem 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 90px;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.875rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step.future .step-circle {
    opacity: 0.5;
}

.step-label {
    margin-top: 0.375rem;
    font-size: 0.75rem;
    color: #6c757d;
    text-align: center;
    white-space: nowrap;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step.future .step-label {
    opacity: 0.5;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    margin: 0 0.25rem;
    margin-bottom: 1.25rem;
    min-width: 20px;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

@using sv_3f6bb331fa14426395b59e916c0fac75.Models
@inject IApplicationService ApplicationService

<h4 class="mb-3">Personal Information</h4>

@if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email"
               class="form-control @(emailError is not null ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (emailError is not null)
        {
            <div class="invalid-feedback">@emailError</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.Address" @bind:event="oninput" />
    </div>
</div>

<div class="mt-4 d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? errorMessage;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        errorMessage = null;
        emailError = null;

        var errors = new List<string>();
        if (string.IsNullOrWhiteSpace(Model.FullName)) errors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(Model.Email)) errors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(Model.Phone)) errors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(Model.Address)) errors.Add("Address is required.");

        if (errors.Count > 0)
        {
            errorMessage = string.Join(" ", errors);
            return;
        }

        isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            isValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_3f6bb331fa14426395b59e916c0fac75.Models

<h4 class="mb-3">Work History</h4>

@if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index"
                   ShowRemove="Entries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private string? errorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        var hasValid = false;
        foreach (var entry in Entries)
        {
            if (!string.IsNullOrWhiteSpace(entry.Company) || !string.IsNullOrWhiteSpace(entry.Title))
            {
                if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate is null)
                {
                    errorMessage = "Each position must have a company name, job title, and start date.";
                    return;
                }
                hasValid = true;
            }
        }

        if (!hasValid)
        {
            errorMessage = "Please add at least one work position with company name, job title, and start date.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_3f6bb331fa14426395b59e916c0fac75.Models

<h4 class="mb-3">References</h4>

@if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]"
                   Index="index"
                   ShowRemove="References.Count > 2"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private string? errorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "All reference fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_3f6bb331fa14426395b59e916c0fac75.Models

@if (SubmittedId is not null)
{
    <div class="text-center py-5">
        <div class="mb-3">
            <span class="display-1 text-success">&#10003;</span>
        </div>
        <h3 class="text-success">Application Submitted!</h3>
        <p class="lead">Your application ID is <strong>#@SubmittedId</strong></p>
        <p class="text-muted">We'll review your application and get back to you soon.</p>
    </div>
}
else
{
    <h4 class="mb-4">Review Your Application</h4>

    @if (submitError is not null)
    {
        <div class="alert alert-danger">@submitError</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @PersonalInfo.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @PersonalInfo.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @PersonalInfo.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @PersonalInfo.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries.Where(e => !string.IsNullOrWhiteSpace(e.Company)))
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <div><strong>@entry.Title</strong> at <strong>@entry.Company</strong></div>
                    <div class="text-muted">
                        @(entry.StartDate?.ToString("MMM yyyy") ?? "N/A") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References.Where(r => !string.IsNullOrWhiteSpace(r.Name)))
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <span class="text-muted">@r.Email &middot; @r.Phone</span>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@(string.IsNullOrWhiteSpace(CoverLetter) ? "(not provided)" : CoverLetter)</p>
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary" @onclick="() => OnEditSection.InvokeAsync(4)">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel PersonalInfo { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public int? SubmittedId { get; set; }

    private string? submitError;

    private async Task HandleSubmit()
    {
        submitError = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
    }
}

namespace sv_3f6bb331fa14426395b59e916c0fac75.Models;

// Service contracts
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
