    @for (int i = 0; i < _stepNames.Length; i++)
    {
        var step = i + 1;
        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;
        var isFuture = step > CurrentStep && !isCompleted;

        <div class="step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
             @onclick="() => HandleStepClick(step)"
             role="@(isCompleted ? "button" : "")"
             style="@(isCompleted ? "cursor:pointer" : "")">
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <div class="step-label">@_stepNames[i]</div>
        </div>

        @if (i < _stepNames.Length - 1)
        {
            <div class="step-connector @(isCompleted ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter] public int CurrentStep { get; set; } = 1;
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] _stepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}
"}

