toolArgs.file_text:
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1rem 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 90px;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.875rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step.future .step-circle {
    opacity: 0.5;
}

.step-label {
    margin-top: 0.375rem;
    font-size: 0.75rem;
    color: #6c757d;
    text-align: center;
    white-space: nowrap;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step.future .step-label {
    opacity: 0.5;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    margin: 0 0.25rem;
    margin-bottom: 1.25rem;
    min-width: 20px;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

