@page "/apply"
@using sv_3f6bb331fa14426395b59e916c0fac75.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo" OnNext="HandleStepCompleted" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries" OnBack="GoBack" OnNext="HandleStepCompleted" />
                break;
            case 3:
                <ReferencesStep References="references" OnBack="GoBack" OnNext="HandleStepCompleted" />
                break;
            case 4:
                <CoverLetterStep @bind-CoverLetter="coverLetter" OnBack="GoBack" OnNext="HandleStepCompleted" />
                break;
            case 5:
                <ReviewStep PersonalInfo="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="@coverLetter"
                            OnEditSection="GoToStep"
                            OnSubmit="HandleSubmit"
                            IsSubmitting="isSubmitting"
                            SubmittedId="submittedId" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new() };
    private List<ReferenceModel> references = new() { new(), new() };
    private string coverLetter = "";

    private bool isSubmitting;
    private int? submittedId;

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void GoBack()
    {
        if (currentStep > 1)
        {
            currentStep--;
        }
    }

    private void HandleStepCompleted()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        try
        {
            var application = new JobApplication(
                new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
                new WorkHistory(workEntries
                    .Where(e => !string.IsNullOrWhiteSpace(e.Company))
                    .Select(e => new WorkEntry(
                        e.Company, e.Title,
                        e.StartDate ?? DateTime.MinValue,
                        e.IsCurrent ? null : e.EndDate,
                        e.Description))
                    .ToList()),
                references
                    .Where(r => !string.IsNullOrWhiteSpace(r.Name))
                    .Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone))
                    .ToList(),
                coverLetter
            );

            submittedId = await ApplicationService.SubmitApplicationAsync(application);
            completedSteps.Add(currentStep);
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

